#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=80010,M=160010,BK=400;int head[N],des[M],nxt[M],cgt,idx[M],ql[N],qr[N],cdt,n,Q,T,P[M],p,A[N],a[N];
struct node{int l,r,t,lc,k,idx;}q[N];struct Node{int p,u,v;}t[N];int dep[N],siz[N],mxs[N],top[N],fa[N],ans[N];
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
inline int bnd(const int&k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
inline void dfs1(const int &u=1,const int &f=0)
{
	siz[u]=1;int mx=0;dep[u]=dep[fa[u]=f]+1;
	grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
}
inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
{
	top[idx[ql[u]=++cdt]=u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);idx[qr[u]=++cdt]=u;
}
inline int LCA(int u,int v){while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];return dep[u]<dep[v]?u:v;}
inline int Dis(int u,int v){return dep[u]+dep[v]-2*dep[LCA(u,v)]+1;}
int sz[M/BK+10],blk,loc[M],qL[M/BK+10],qR[M/BK+10],cnt[N],L,R,Tm;bool vis[M];
inline void Init(){rep(1,p,i)loc[i]=(i-1)/BK+1;blk=loc[p];rep(1,blk,i)qL[i]=qR[i-1]+1,qR[i]=i*BK;qR[blk]=p;}
inline int qry(int K){rep(1,blk,B)if(sz[B]>=K){rep(qL[B],qR[B],i){if(cnt[i]>=K)return p-i+1;K-=cnt[i];}}else K-=sz[B];return -1;}
inline void add(const int &p,const int &w){cnt[p]+=w;sz[loc[p]]+=w;}
inline void ins(const int &p){add(a[p],vis[p]?-1:1);vis[p]^=1;}
inline void Tadd(){++Tm;int p=t[Tm].p,v=t[Tm].v;if(vis[p])add(a[p],-1),add(v,1);a[p]=v;}
inline void Tmns(){int p=t[Tm].p,u=t[Tm].u;--Tm;if(vis[p])add(a[p],-1),add(u,1);a[p]=u;}
int main()
{
	p=n=read();int nQ=read();rep(1,n,i)P[i]=a[i]=A[i]=read();rep(2,n,i)ins(read(),read());dfs1();dfs2();
	while(nQ--)
	{
		int K=read();if(K==0){int x=read(),v=P[++p]=read();t[++T]=(Node){x,A[x],v};A[x]=v;}
		else
		{
			int u=read(),v=read();++Q;if(ql[u]>ql[v]){int tmp(u);u=v;v=tmp;}
			q[Q]=((ql[u]<=ql[v]&&qr[v]<=qr[u])?((node){ql[u],ql[v],T,0,K,Q}):((node){qr[u],ql[v],T,LCA(u,v),K,Q}));
		}
	}
	std::sort(P+1,P+p+1);p=std::unique(P+1,P+p+1)-P-1;Init();
	rep(1,n,i)a[i]=p-bnd(a[i])+1;rep(1,T,i)t[i].u=p-bnd(t[i].u)+1,t[i].v=p-bnd(t[i].v)+1;
	std::sort(q+1,q+Q+1,[&](const node&x,const node&y){return (x.l>>11)==(y.l>>11)?((x.r>>11)==(y.r>>11)?x.t<y.t:x.r<y.r):x.l<y.l;});
	L=q[1].l,R=q[1].l-1,Tm=0;rep(1,Q,i)
	{
		while(R<q[i].r)ins(idx[++R]);while(L>q[i].l)ins(idx[--L]);
		while(R>q[i].r)ins(idx[R--]);while(L<q[i].l)ins(idx[L++]);
		while(Tm<q[i].t)Tadd();while(Tm>q[i].t)Tmns();
		if(q[i].lc)ins(q[i].lc);ans[q[i].idx]=qry(q[i].k);if(q[i].lc)ins(q[i].lc);
	}
	rep(1,Q,i)if(~ans[i])printf("%d\n",P[ans[i]]);else puts("invalid request!");
}
